    }
  }
}

/**
 * pi-web-research extension entry point.
 * Delegates all registration to src/extension/register.ts.
 */
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { registerPiWebResearch } from "./src/extension/register.ts";

export default function (pi: ExtensionAPI): void {
	registerPiWebResearch(pi);
}

// ── Shared Types ──────────────────────────────────────────────────────────────

/** A single search result from any engine. */
export interface SearchResult {
	title: string;
	url: string;
	snippet: string;
	source: string; // engine name
	date?: string;
}

/** Options passed to a search engine. */
export interface SearchOptions {
	maxResults?: number;
	recency?: "day" | "week" | "month" | "year" | "all";
}

/** Content extracted from a URL. */
export interface ExtractedContent {
	title: string;
	url: string;
	content: string;
	contentType: "text" | "html" | "markdown";
	contentLength: number;
	truncated: boolean;
}

/** Token budget enforcement result. */
export interface BudgetResult {
	content: string;
	truncated: boolean;
	originalLength: number;
	finalLength: number;
	originalTokens: ***;
	finalTokens: ***;
}

/** GitHub-specific content. */
export interface GitHubContent {
	type: "readme" | "file" | "issue" | "pull" | "wiki" | "tree";
	owner: string;
	repo: string;
	path?: string;
	title: string;
	content: string;
	url: string;
	metadata?: Record<string, unknown>;
}

/** Research report produced by web_research. */
export interface ResearchReport {
	query: string;
	depth: "quick" | "standard" | "deep";
	summary: string;
	findings: ResearchFinding[];
	contradictions: string[];
	recommendations: string[];
	sources: ResearchSource[];
	generatedAt: string;
}

/** A single finding from a source. */
export interface ResearchFinding {
	topic: string;
	content: string;
	sources: string[]; // URLs
	confidence: "high" | "medium" | "low";
}

/** A cited source. */
export interface ResearchSource {
	title: string;
	url: string;
	snippet: string;
	retrievedAt: string;
}

/** Cache entry stored in SQLite. */
export interface CacheEntry {
	url: string;
	content: string;
	contentType: string;
	fetchedAt: number;
	expiresAt: number;
	sizeBytes: number;
}

/** Extension configuration shape. */
export interface WebResearchConfig {
	enabled: boolean;
	search: {
		defaultEngine: "auto" | "brave" | "gemini" | "exa" | "duckduckgo";
		fallbackChain: string[];
		maxResults: number;
	};
	fetch: {
		maxTokens: ***;
		timeout: number;
		userAgent: string;
	};
	cache: {
		enabled: boolean;
		maxAgeHours: number;
		maxSizeMB: number;
	};
	apiKeys: ***
		brave: string;
		gemini: string;
		exa: string;
	};
	fallback: {
		onAllProvidersFail: string;
		suggestion: string;
	};
}

/** Fetch extraction options. */
export interface ExtractOptions {
	maxTokens?: number;
	format?: "text" | "html" | "markdown";
	selector?: string;
}

import * as fs from "node:fs";
import * as path from "node:path";
import type { WebResearchConfig } from "./types.ts";

/** Default configuration values. */
const DEFAULTS: WebResearchConfig = {
	enabled: true,
	search: {
		defaultEngine: "auto",
		fallbackChain: ["brave", "gemini", "exa", "duckduckgo"],
		maxResults: 5,
	},
	fetch: {
		maxTokens: ***,
		timeout: 15000,
		userAgent: "Pi Coding Agent/1.0",
	},
	cache: {
		enabled: true,
		maxAgeHours: 24,
		maxSizeMB: 50,
	},
	apiKeys: ***
		brave: "",
		gemini: "",
		exa: "",
	},
	fallback: {
		onAllProvidersFail: "return_empty_with_suggestion",
		suggestion: "No search providers available. Set API keys in config or env vars.",
	},
};

/** Resolve an API key: explicit config value takes priority, then env var. */
function resolveKey(configVal: string, envVar: string): string {
	if (configVal && configVal.trim().length > 0) return configVal.trim();
	return process.env[envVar] ?? "";
}

/** Deep-merge a partial user config over defaults. */
function mergeConfig(user: Record<string, unknown>): WebResearchConfig {
	const result: WebResearchConfig = JSON.parse(JSON.stringify(DEFAULTS));

	if (user.enabled !== undefined) {
		result.enabled = Boolean(user.enabled);
	}
	if (user.search && typeof user.search === "object") {
		const s = user.search as Record<string, unknown>;
		if (s.defaultEngine !== undefined) result.search.defaultEngine = s.defaultEngine as WebResearchConfig["search"]["defaultEngine"];
		if (s.fallbackChain !== undefined) result.search.fallbackChain = s.fallbackChain as string[];
		if (s.maxResults !== undefined) result.search.maxResults = Number(s.maxResults);
	}
	if (user.fetch && typeof user.fetch === "object") {
		const f = user.fetch as Record<string, unknown>;
		if (f.maxTokens !== undefined) result.fetch.maxTokens = ***;
		if (f.timeout !== undefined) result.fetch.timeout = Number(f.timeout);
		if (f.userAgent !== undefined) result.fetch.userAgent = String(f.userAgent);
	}
	if (user.cache && typeof user.cache === "object") {
		const c = user.cache as Record<string, unknown>;
		if (c.enabled !== undefined) result.cache.enabled = Boolean(c.enabled);
		if (c.maxAgeHours !== undefined) result.cache.maxAgeHours = Number(c.maxAgeHours);
		if (c.maxSizeMB !== undefined) result.cache.maxSizeMB = Number(c.maxSizeMB);
	}
	if (user.apiKeys && typeof user.apiKeys =*** "object") {
		const k = user.apiKeys as Record<string, unknown>;
		if (k.brave !== undefined) result.apiKeys.brave = ***;
		if (k.gemini !== undefined) result.apiKeys.gemini = ***;
		if (k.exa !== undefined) result.apiKeys.exa = ***;
	}
	if (user.fallback && typeof user.fallback === "object") {
		const fb = user.fallback as Record<string, unknown>;
		if (fb.onAllProvidersFail !== undefined) result.fallback.onAllProvidersFail = String(fb.onAllProvidersFail);
		if (fb.suggestion !== undefined) result.fallback.suggestion = String(fb.suggestion);
	}

	// Resolve API keys from env vars
	result.apiKeys.brave = ***, "BRAVE_API_KEY");
	result.apiKeys.gemini = ***, "GEMINI_API_KEY");
	result.apiKeys.exa = ***, "EXA_API_KEY");

	return result;
}

/** Load configuration from `.pi/pi-web-research.json` in the given cwd. */
export function loadConfig(cwd: string): WebResearchConfig {
	const configPath = path.join(cwd, ".pi", "pi-web-research.json");
	try {
		if (fs.existsSync(configPath)) {
			const raw = fs.readFileSync(configPath, "utf-8");
			const parsed: unknown = JSON.parse(raw);
			if (parsed && typeof parsed === "object") {
				return mergeConfig(parsed as Record<string, unknown>);
			}
		}
	} catch {
		// Return defaults on parse errors
	}
	return mergeConfig({});
}

/** Return a copy of the default config (for testing). */
export function getDefaults(): WebResearchConfig {
	return JSON.parse(JSON.stringify(DEFAULTS));
}

import type { SearchResult, SearchOptions } from "../types.ts";

/** Interface that every search engine must implement. */
export interface SearchEngine {
	/** Human-readable engine name. */
	readonly name: string;

	/** Return true if this engine has valid credentials / is usable. */
	isAvailable(): boolean;

	/** Execute a search and return results. */
	search(query: string, opts?: SearchOptions): Promise<SearchResult[]>;
}

import type { SearchEngine } from "./engine.ts";
import type { SearchResult, SearchOptions } from "../types.ts";

/** Brave Search API implementation. */
export class BraveSearchEngine implements SearchEngine {
	readonly name = "brave";
	private readonly apiKey: ***;

	constructor(apiKey: string) {
		this.apiKey = ***;
	}

	isAvailable(): boolean {
		return this.apiKey.length > 0;
	}

	async search(query: string, opts?: SearchOptions): Promise<SearchResult[]> {
		const maxResults = opts?.maxResults ?? 5;
		const params = new URLSearchParams({
			q: query,
			count: String(maxResults),
		});
		if (opts?.recency && opts.recency !== "all") {
			params.set("freshness", opts.recency);
		}

		const response = await fetch(
			`https://api.search.brave.com/res/v1/web/search?${params.toString()}`,
			{
				headers: {
					"Accept": "application/json",
					"Accept-Encoding": "gzip",
					"X-Subscription-Token": this.apiKey,
				},
				signal: AbortSignal.timeout(10000),
			},
		);

		if (!response.ok) {
			throw new Error(`Brave API error: ${response.status} ${response.statusText}`);
		}

		const data = await response.json() as Record<string, unknown>;
		const web = (data.web as Record<string, unknown> | undefined)?.results;
		if (!Array.isArray(web)) return [];

		return web.slice(0, maxResults).map((item: unknown) => {
			const r = item as Record<string, string>;
			return {
				title: r.title ?? "",
				url: r.url ?? "",
				snippet: r.description ?? "",
				source: "brave",
				date: r.age ?? undefined,
			};
		});
	}
}

import type { SearchEngine } from "./engine.ts";
import type { SearchResult, SearchOptions } from "../types.ts";

/** Google Gemini search implementation using the Generative Language API. */
export class GeminiSearchEngine implements SearchEngine {
	readonly name = "gemini";
	private readonly apiKey: ***;

	constructor(apiKey: string) {
		this.apiKey = ***;
	}

	isAvailable(): boolean {
		return this.apiKey.length > 0;
	}

	async search(query: string, opts?: SearchOptions): Promise<SearchResult[]> {
		const maxResults = opts?.maxResults ?? 5;

		const response = await fetch(
			`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${this.apiKey}`,
			{
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body: JSON.stringify({
					contents: [{ parts: [{ text: `Search for: ${query}. List the top ${maxResults} results with title, URL, and a short snippet for each.` }] }],
					tools: [{ google_search: {} }],
				}),
				signal: AbortSignal.timeout(15000),
			},
		);

		if (!response.ok) {
			throw new Error(`Gemini API error: ${response.status} ${response.statusText}`);
		}

		const data = await response.json() as Record<string, unknown>;
		const candidates = data.candidates as Array<Record<string, unknown>> | undefined;
		if (!candidates?.length) return [];

		const content = candidates[0]?.content;
		const parts = (content as Record<string, unknown>)?.parts as Array<Record<string, unknown>> | undefined;
		if (!parts?.length) return [];

		// Extract grounding metadata for actual URLs
		const groundingMeta = candidates[0]?.groundingMetadata as Record<string, unknown> | undefined;
		const groundingChunks = groundingMeta?.groundingChunks as Array<Record<string, unknown>> | undefined;
		const webEntries = groundingChunks?.filter((c) => c.web) ?? [];

		// Build text response
		const textPart = parts.find((p) => typeof p.text === "string");
		const text = (textPart?.text as string) ?? "";

		// Parse structured results from the text response combined with grounding URLs
		const results: SearchResult[] = [];
		const lines = text.split("\n").filter((l: string) => l.trim().length > 0);

		for (const line of lines) {
			if (results.length >= maxResults) break;
			// Try to detect numbered items or bullet points with URLs
			const urlMatch = line.match(/\(?(https?:\/\/[^\s)]+)\)?/);
			const titleMatch = line.match(/^\s*(?:\d+[\.\)]\s*|[-*]\s*)(.+)/);

			if (urlMatch) {
				const url = urlMatch[1];
				const title = titleMatch?.[1]?.replace(urlMatch[0], "").trim() || url;
				results.push({
					title,
					url,
					snippet: line.replace(urlMatch[0], "").replace(/^\s*(?:\d+[\.\)]\s*|[-*]\s*)/, "").trim(),
					source: "gemini",
				});
			}
		}

		// If we couldn't parse structured results, use grounding chunks
		if (results.length === 0 && webEntries.length > 0) {
			for (const entry of webEntries) {
				if (results.length >= maxResults) break;
				const web = entry.web as Record<string, string> | undefined;
				if (web?.uri) {
					results.push({
						title: web.title ?? web.uri,
						url: web.uri,
						snippet: web.title ?? "",
						source: "gemini",
					});
				}
			}
		}

		// Fallback: return text as single result if nothing structured
		if (results.length === 0 && text.length > 0) {
			results.push({
				title: query,
				url: "",
				snippet: text.slice(0, 500),
				source: "gemini",
			});
		}

		return results;
	}
}

import type { SearchEngine } from "./engine.ts";
import type { SearchResult, SearchOptions } from "../types.ts";

/** Exa AI search implementation. */
export class ExaSearchEngine implements SearchEngine {
	readonly name = "exa";
	private readonly apiKey: ***;

	constructor(apiKey: string) {
		this.apiKey = ***;
	}

	isAvailable(): boolean {
		return this.apiKey.length > 0;
	}

	async search(query: string, opts?: SearchOptions): Promise<SearchResult[]> {
		const maxResults = opts?.maxResults ?? 5;

		const response = await fetch("https://api.exa.ai/search", {
			method: "POST",
			headers: {
				"Content-Type": "application/json",
				"x-api-key": this.apiKey,
			},
			body: JSON.stringify({
				query,
				numResults: maxResults,
				type: "auto",
				contents: {
					text: { maxCharacters: 200 },
				},
			}),
			signal: AbortSignal.timeout(15000),
		});

		if (!response.ok) {
			throw new Error(`Exa API error: ${response.status} ${response.statusText}`);
		}

		const data = await response.json() as Record<string, unknown>;
		const results = data.results as Array<Record<string, unknown>> | undefined;
		if (!Array.isArray(results)) return [];

		return results.slice(0, maxResults).map((item) => {
			const r = item as Record<string, unknown>;
			return {
				title: String(r.title ?? ""),
				url: String(r.url ?? ""),
				snippet: String((r.text as string ?? "").slice(0, 300)),
				source: "exa",
				date: r.publishedDate ? String(r.publishedDate) : undefined,
			};
		});
	}
}

import type { SearchEngine } from "./engine.ts";
import type { SearchResult, SearchOptions } from "../types.ts";

/**
 * DuckDuckGo HTML-scrape fallback engine.
 * No API key required. Parses the DDG HTML results page.
 * Note: DDG HTML structure may change — this is a best-effort fallback.
 */
export class DuckDuckGoSearchEngine implements SearchEngine {
	readonly name = "duckduckgo";

	isAvailable(): boolean {
		// Always available — no API key needed
		return true;
	}

	async search(query: string, opts?: SearchOptions): Promise<SearchResult[]> {
		const maxResults = opts?.maxResults ?? 5;
		const params = new URLSearchParams({ q: query, no_redirect: "1" });

		const response = await fetch(
			`https://html.duckduckgo.com/html/?${params.toString()}`,
			{
				headers: {
					"User-Agent": "Mozilla/5.0 (compatible; PiBot/1.0)",
					"Accept": "text/html",
				},
				signal: AbortSignal.timeout(10000),
			},
		);

		if (!response.ok) {
			throw new Error(`DuckDuckGo error: ${response.status} ${response.statusText}`);
		}

		const html = await response.text();
		return this.parseResults(html, maxResults);
	}

	private parseResults(html: string, maxResults: number): SearchResult[] {
		const results: SearchResult[] = [];

		// DDG HTML uses <a class="result__a"> for titles and
		// <a class="result__url"> for URLs, <td class="result__snippet"> for snippets
		const resultRegex = /<a[^>]+class="result__a"[^>]*href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/gi;
		const snippetRegex = /<td[^>]+class="result__snippet"[^>]*>([\s\S]*?)<\/td>/gi;
		const urlRegex = /<a[^>]+class="result__url"[^>]*>([\s\S]*?)<\/a>/gi;

		const titles: Array<{ url: string; title: string }> = [];
		let match: RegExpExecArray | null;

		while ((match = resultRegex.exec(html)) !== null) {
			titles.push({
				url: this.unescapeHtml(match[1]),
				title: this.stripTags(match[2]),
			});
		}

		const snippets: string[] = [];
		while ((match = snippetRegex.exec(html)) !== null) {
			snippets.push(this.stripTags(match[1]));
		}

		for (let i = 0; i < Math.min(titles.length, maxResults); i++) {
			results.push({
				title: titles[i]?.title ?? "",
				url: titles[i]?.url ?? "",
				snippet: snippets[i] ?? "",
				source: "duckduckgo",
			});
		}

		return results;
	}

	private stripTags(html: string): string {
		return html
			.replace(/<[^>]+>/g, "")
			.replace(/&amp;/g, "&")
			.replace(/&lt;/g, "<")
			.replace(/&gt;/g, ">")
			.replace(/&quot;/g, '"')
			.replace(/&#39;/g, "'")
			.replace(/\s+/g, " ")
			.trim();
	}

	private unescapeHtml(s: string): string {
		return s
			.replace(/&amp;/g, "&")
			.replace(/&lt;/g, "<")
			.replace(/&gt;/g, ">")
			.replace(/&quot;/g, '"')
			.replace(/&#39;/g, "'");
	}
}

import type { SearchEngine } from "./engine.ts";
import type { SearchResult, SearchOptions } from "../types.ts";
import { BraveSearchEngine } from "./brave.ts";
import { GeminiSearchEngine } from "./gemini.ts";
import { ExaSearchEngine } from "./exa.ts";
import { DuckDuckGoSearchEngine } from "./duckduckgo.ts";

export interface FallbackChainConfig {
	/** Ordered list of engine names to try. */
	chain: string[];
	/** API keys keyed by engine name. */
	apiKeys: ***, string>;
}

/** Build an engine instance by name. */
export function createEngine(name: string, apiKeys: ***, string>): SearchEngine {
	switch (name) {
		case "brave": return new BraveSearchEngine(apiKeys.brave ?? "");
		case "gemini": return new GeminiSearchEngine(apiKeys.gemini ?? "");
		case "exa": return new ExaSearchEngine(apiKeys.exa ?? "");
		case "duckduckgo": return new DuckDuckGoSearchEngine();
		default:
			throw new Error(`Unknown search engine: ${name}`);
	}
}

/** Result when all engines in the chain fail. */
export interface FallbackFailure {
	results: SearchResult[];
	triedEngines: string[];
	suggestion: string;
}

/**
 * Execute search across engines in fallback order.
 * - Skips engines where isAvailable() returns false.
 * - If an engine throws, catches the error and tries the next.
 * - Returns results from the first successful engine.
 */
export async function fallbackSearch(
	config: FallbackChainConfig,
	query: string,
	opts?: SearchOptions,
): Promise<SearchResult[] | FallbackFailure> {
	const triedEngines: string[] = [];

	for (const engineName of config.chain) {
		let engine: SearchEngine;
		try {
			engine = createEngine(engineName, config.apiKeys);
		} catch {
			continue; // Unknown engine name, skip
		}

		if (!engine.isAvailable()) {
			continue; // No API key or not ready
		}

		triedEngines.push(engineName);
		try {
			const results = await engine.search(query, opts);
			if (results.length > 0) {
				return results;
			}
			// Empty results — try next engine
		} catch {
			// Engine error — try next
		}
	}

	// All engines failed or returned empty
	return {
		results: [],
		triedEngines,
		suggestion: "No search providers available. Set API keys in config or env vars.",
	};
}

import type { WebResearchConfig } from "../types.ts";

export interface FetchResult {
	url: string;
	content: string;
	contentType: string; // "text/html", "text/plain", "application/json", etc.
	statusCode: number;
}

/**
 * Fetch raw content from a URL.
 * Uses Node.js built-in fetch with configurable timeout and User-Agent.
 */
export async function fetchUrl(
	url: string,
	config: WebResearchConfig,
): Promise<FetchResult> {
	const controller = new AbortController();
	const timer = setTimeout(() => controller.abort(), config.fetch.timeout);

	try {
		const response = await fetch(url, {
			headers: {
				"User-Agent": config.fetch.userAgent,
				"Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,text/plain;q=0.8,application/json;q=0.7,*/*;q=0.1",
				"Accept-Encoding": "gzip, deflate",
			},
			redirect: "follow",
			signal: controller.signal,
		});

		const contentType = response.headers.get("content-type") ?? "text/plain";
		const content = await response.text();

		return {
			url: response.url, // Final URL after redirects
			content,
			contentType,
			statusCode: response.status,
		};
	} finally {
		clearTimeout(timer);
	}
}

// LAZY: linkedom is heavy — only imported when actually needed for HTML parsing
import { parseHTML } from "linkedom";
import type { ExtractedContent, ExtractOptions } from "../types.ts";
import { enforceBudget } from "./budget.ts";

/** Noise elements to strip from HTML before extraction. */
const NOISE_SELECTORS = [
	"script", "style", "nav", "footer", "header",
	".ad", ".ads", ".advertisement", ".sidebar", ".popup",
	".cookie-banner", ".social-share", ".newsletter",
	"[role='navigation']", "[role='banner']", "[role='contentinfo']",
];

/**
 * Extract meaningful content from raw HTML.
 * 1. Parse HTML with linkedom
 * 2. Remove noise elements
 * 3. Apply CSS selector if provided, otherwise find main content
 * 4. Convert to requested format
 * 5. Enforce token budget
 */
export function extractContent(
	html: string,
	url: string,
	opts: ExtractOptions = {},
): ExtractedContent {
	const format = opts.format ?? "text";
	const maxTokens = *** ?? 5000;

	const { document } = parseHTML(html);

	// Extract title
	const titleEl = document.querySelector("title");
	const title = titleEl?.textContent?.trim() ?? url;

	// Remove noise
	for (const selector of NOISE_SELECTORS) {
		try {
			const elements = document.querySelectorAll(selector);
			for (const el of elements) {
				el.parentNode?.removeChild(el);
			}
		} catch {
			// Invalid selector — skip
		}
	}

	let contentElement: globalThis.Element | null;

	// If a CSS selector is provided, use it
	if (opts.selector) {
		contentElement = document.querySelector(opts.selector);
		if (!contentElement) {
			// Fallback to body
			contentElement = document.querySelector("body") ?? document.documentElement;
		}
	} else {
		// Find main content via heuristic
		contentElement = findMainContent(document);
	}

	// Convert to requested format
	let content: string;
	switch (format) {
		case "html":
			content = contentElement?.innerHTML ?? "";
			break;
		case "markdown":
			content = htmlToMarkdown(contentElement?.innerHTML ?? "");
			break;
		case "text":
		default:
			content = contentElement?.textContent ?? "";
			break;
	}

	// Clean up whitespace
	content = content.replace(/\n{3,}/g, "\n\n").replace(/[ \t]+/g, " ").trim();

	// Enforce budget
	const budgetResult = enforceBudget(content, maxTokens);

	return {
		title,
		url,
		content: budgetResult.content,
		contentType: format,
		contentLength: budgetResult.finalLength,
		truncated: budgetResult.truncated,
	};
}

/**
 * Find the main content element using heuristics:
 * 1. Look for <article>, <main>, or role="main"
 * 2. Look for the element with the most text content
 */
function findMainContent(document: globalThis.Document): globalThis.Element {
	// Try semantic elements first
	const candidates = [
		document.querySelector("article"),
		document.querySelector("main"),
		document.querySelector("[role='main']"),
		document.querySelector(".post-content"),
		document.querySelector(".article-content"),
		document.querySelector(".entry-content"),
		document.querySelector(".content"),
	];

	for (const el of candidates) {
		if (el && (el.textContent?.length ?? 0) > 100) {
			return el;
		}
	}

	// Fallback: find the div/section with the most text
	const body = document.querySelector("body") ?? document.documentElement;
	let best = body as globalThis.Element;
	let bestLen = body.textContent?.length ?? 0;

	const divs = body.querySelectorAll("div, section");
	for (const div of divs) {
		const len = div.textContent?.length ?? 0;
		if (len > bestLen) {
			bestLen = len;
			best = div;
		}
	}

	return best;
}

/**
 * Minimal HTML to Markdown conversion.
 * Handles headings, paragraphs, lists, links, bold, italic, code.
 */
export function htmlToMarkdown(html: string): string {
	let md = html;

	// Headings
	md = md.replace(/<h([1-6])[^>]*>([\s\S]*?)<\/h\1>/gi, (_match, level: string, content: string) => {
		const hashes = "#".repeat(Number(level));
		return `\n${hashes} ${content.trim()}\n`;
	});

	// Paragraphs
	md = md.replace(/<p[^>]*>([\s\S]*?)<\/p>/gi, "\n$1\n");

	// Links
	md = md.replace(/<a[^>]+href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/gi, "[$2]($1)");

	// Bold
	md = md.replace(/<(strong|b)[^>]*>([\s\S]*?)<\/\1>/gi, "**$2**");

	// Italic
	md = md.replace(/<(em|i)[^>]*>([\s\S]*?)<\/\1>/gi, "*$2*");

	// Code blocks
	md = md.replace(/<pre[^>]*><code[^>]*>([\s\S]*?)<\/code><\/pre>/gi, "\n```\n$1\n```\n");
	md = md.replace(/<code[^>]*>([\s\S]*?)<\/code>/gi, "`$1`");

	// List items
	md = md.replace(/<li[^>]*>([\s\S]*?)<\/li>/gi, "- $1");

	// Line breaks
	md = md.replace(/<br\s*\/?>/gi, "\n");

	// Strip remaining tags
	md = md.replace(/<[^>]+>/g, "");

	// Decode entities
	md = md.replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">")
		.replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, " ");

	// Clean whitespace
	md = md.replace(/\n{3,}/g, "\n\n").trim();

	return md;
}

import type { GitHubContent, ExtractOptions } from "../types.ts";
import { enforceBudget } from "./budget.ts";

/** Parsed GitHub URL components. */
interface GitHubUrlParts {
	type: "readme" | "file" | "issue" | "pull" | "wiki" | "tree";
	owner: string;
	repo: string;
	path?: string;
	number?: number;
}

/**
 * Detect if a URL is a GitHub URL and parse it.
 * Returns null if not a GitHub URL.
 */
export function parseGitHubUrl(url: string): GitHubUrlParts | null {
	try {
		const parsed = new URL(url);
		if (parsed.hostname !== "github.com" && parsed.hostname !== "www.github.com") {
			return null;
		}

		const parts = parsed.pathname.split("/").filter(Boolean);
		if (parts.length < 2) return null;

		const [owner, repo, section, ...rest] = parts;

		// /owner/repo → tree (README + file listing)
		if (!section) {
			return { type: "readme", owner, repo };
		}

		// /owner/repo/tree/<branch>/path
		if (section === "tree") {
			// skip branch name
			const filePath = rest.length > 1 ? rest.slice(1).join("/") : undefined;
			return { type: "tree", owner, repo, path: filePath };
		}

		// /owner/repo/blob/<branch>/path
		if (section === "blob") {
			const filePath = rest.length > 1 ? rest.slice(1).join("/") : undefined;
			return { type: "file", owner, repo, path: filePath };
		}

		// /owner/repo/issues/N
		if (section === "issues" && rest[0]) {
			const num = Number(rest[0]);
			if (!Number.isNaN(num)) {
				return { type: "issue", owner, repo, number: num };
			}
		}

		// /owner/repo/pull/N
		if (section === "pull" && rest[0]) {
			const num = Number(rest[0]);
			if (!Number.isNaN(num)) {
				return { type: "pull", owner, repo, number: num };
			}
		}

		// /owner/repo/wiki
		if (section === "wiki") {
			return { type: "wiki", owner, repo, path: rest.join("/") || undefined };
		}

		return null;
	} catch {
		return null;
	}
}

/**
 * Fetch and extract GitHub content.
 * Uses the GitHub REST API (no auth required for public repos).
 */
export async function extractGitHub(
	url: string,
	opts: ExtractOptions = {},
	token?: string,
): Promise<GitHubContent> {
	const parsed = parseGitHubUrl(url);
	if (!parsed) {
		throw new Error(`Not a GitHub URL: ${url}`);
	}

	const maxTokens = *** ?? 5000;
	const headers: Record<string, string> = {
		"Accept": "application/vnd.github.v3+json",
		"User-Agent": "Pi-Web-Research/1.0",
	};
	if (token) {
		headers["Authorization"] = `Bearer ${token}`;
	}

	const apiBase = "https://api.github.com";

	switch (parsed.type) {
		case "readme":
			return fetchReadme(apiBase, parsed.owner, parsed.repo, headers, maxTokens);
		case "tree":
			return fetchTree(apiBase, parsed.owner, parsed.repo, headers, maxTokens);
		case "file":
			return fetchFile(apiBase, parsed.owner, parsed.repo, parsed.path ?? "", headers, maxTokens);
		case "issue":
			return fetchIssue(apiBase, parsed.owner, parsed.repo, parsed.number!, headers, maxTokens);
		case "pull":
			return fetchPull(apiBase, parsed.owner, parsed.repo, parsed.number!, headers, maxTokens);
		case "wiki":
			return fetchWiki(parsed.owner, parsed.repo, parsed.path, maxTokens);
	}
}

async function fetchReadme(
	apiBase: string, owner: string, repo: string,
	headers: Record<string, string>, maxTokens: ***,
): Promise<GitHubContent> {
	// Fetch README
	const readmeRes = await fetch(`${apiBase}/repos/${owner}/${repo}/readme`, {
		headers, signal: AbortSignal.timeout(10000),
	});
	if (!readmeRes.ok) throw new Error(`GitHub API error: ${readmeRes.status}`);
	const readmeData = await readmeRes.json() as Record<string, unknown>;
	const readmeContent = atob(readmeData.content as string);

	// Fetch file tree (2 levels max)
	const treeRes = await fetch(
		`${apiBase}/repos/${owner}/${repo}/git/trees/HEAD?recursive=1`,
		{ headers, signal: AbortSignal.timeout(10000) },
	);
	let treeText = "";
	if (treeRes.ok) {
		const treeData = await treeRes.json() as Record<string, unknown>;
		const tree = treeData.tree as Array<Record<string, unknown>> | undefined;
		if (tree) {
			const paths = tree
				.filter((t) => (String(t.path ?? "").split("/").length) <= 2)
				.map((t) => `${t.type === "tree" ? "📁" : "📄"} ${t.path}`)
				.join("\n");
			treeText = `\n\n## File Tree\n${paths}`;
		}
	}

	const fullContent = `# ${owner}/${repo}\n\n${readmeContent}${treeText}`;
	const budget = enforceBudget(fullContent, maxTokens);

	return {
		type: "readme",
		owner,
		repo,
		title: `${owner}/${repo}`,
		content: budget.content,
		url: `https://github.com/${owner}/${repo}`,
		metadata: { truncated: budget.truncated },
	};
}

async function fetchTree(
	apiBase: string, owner: string, repo: string,
	headers: Record<string, string>, maxTokens: ***,
): Promise<GitHubContent> {
	const treeRes = await fetch(
		`${apiBase}/repos/${owner}/${repo}/git/trees/HEAD?recursive=1`,
		{ headers, signal: AbortSignal.timeout(10000) },
	);
	if (!treeRes.ok) throw new Error(`GitHub API error: ${treeRes.status}`);
	const treeData = await treeRes.json() as Record<string, unknown>;
	const tree = treeData.tree as Array<Record<string, unknown>> | undefined;
	if (!tree) throw new Error("Empty tree response");

	const content = tree
		.map((t) => `${t.type === "tree" ? "📁" : "📄"} ${t.path}`)
		.join("\n");
	const budget = enforceBudget(content, maxTokens);

	return {
		type: "tree",
		owner,
		repo,
		title: `${owner}/${repo} — File Tree`,
		content: budget.content,
		url: `https://github.com/${owner}/${repo}`,
		metadata: { fileCount: tree.length, truncated: budget.truncated },
	};
}

async function fetchFile(
	apiBase: string, owner: string, repo: string,
	filePath: string, headers: Record<string, string>, maxTokens: ***,
): Promise<GitHubContent> {
	const res = await fetch(
		`${apiBase}/repos/${owner}/${repo}/contents/${filePath}`,
		{ headers, signal: AbortSignal.timeout(10000) },
	);
	if (!res.ok) throw new Error(`GitHub API error: ${res.status}`);
	const data = await res.json() as Record<string, unknown>;
	const content = atob(data.content as string);
	const budget = enforceBudget(content, maxTokens);

	return {
		type: "file",
		owner,
		repo,
		path: filePath,
		title: `${owner}/${repo}/${filePath}`,
		content: budget.content,
		url: `https://github.com/${owner}/${repo}/blob/HEAD/${filePath}`,
		metadata: { size: data.size, truncated: budget.truncated },
	};
}

async function fetchIssue(
	apiBase: string, owner: string, repo: string,
	issueNumber: number, headers: Record<string, string>, maxTokens: ***,
): Promise<GitHubContent> {
	const [issueRes, commentsRes] = await Promise.all([
		fetch(`${apiBase}/repos/${owner}/${repo}/issues/${issueNumber}`, {
			headers, signal: AbortSignal.timeout(10000),
		}),
		fetch(`${apiBase}/repos/${owner}/${repo}/issues/${issueNumber}/comments?per_page=10`, {
			headers, signal: AbortSignal.timeout(10000),
		}),
	]);

	if (!issueRes.ok) throw new Error(`GitHub API error: ${issueRes.status}`);
	const issue = await issueRes.json() as Record<string, unknown>;

	let content = `# Issue #${issueNumber}: ${issue.title}\n\n`;
	content += `**State:** ${issue.state} | **Author:** ${(issue.user as Record<string, unknown>)?.login ?? "unknown"}\n\n`;
	content += String(issue.body ?? "") + "\n";

	if (commentsRes.ok) {
		const comments = await commentsRes.json() as Array<Record<string, unknown>>;
		if (comments.length > 0) {
			content += "\n---\n## Comments\n\n";
			for (const c of comments.slice(0, 10)) {
				const author = (c.user as Record<string, unknown>)?.login ?? "unknown";
				content += `**@${author}:**\n${String(c.body ?? "")}\n\n`;
			}
		}
	}

	const budget = enforceBudget(content, maxTokens);

	return {
		type: "issue",
		owner,
		repo,
		number: issueNumber,
		title: `Issue #${issueNumber}: ${issue.title}`,
		content: budget.content,
		url: `https://github.com/${owner}/${repo}/issues/${issueNumber}`,
		metadata: { state: issue.state, truncated: budget.truncated },
	};
}

async function fetchPull(
	apiBase: string, owner: string, repo: string,
	prNumber: number, headers: Record<string, string>, maxTokens: ***,
): Promise<GitHubContent> {
	const [prRes, filesRes] = await Promise.all([
		fetch(`${apiBase}/repos/${owner}/${repo}/pulls/${prNumber}`, {
			headers, signal: AbortSignal.timeout(10000),
		}),
		fetch(`${apiBase}/repos/${owner}/${repo}/pulls/${prNumber}/files?per_page=20`, {
			headers, signal: AbortSignal.timeout(10000),
		}),
	]);

	if (!prRes.ok) throw new Error(`GitHub API error: ${prRes.status}`);
	const pr = await prRes.json() as Record<string, unknown>;

	let content = `# PR #${prNumber}: ${pr.title}\n\n`;
	content += `**State:** ${pr.state} | **Author:** ${(pr.user as Record<string, unknown>)?.login ?? "unknown"} | **Branch:** ${pr.head?.ref} → ${pr.base?.ref}\n\n`;
	content += String(pr.body ?? "") + "\n";

	if (filesRes.ok) {
		const files = await filesRes.json() as Array<Record<string, unknown>>;
		if (files.length > 0) {
			content += "\n---\n## Changed Files\n\n";
			for (const f of files) {
				content += `- \`${f.filename}\` (+${f.additions}/-${f.deletions}) ${f.status}\n`;
			}
		}
	}

	const budget = enforceBudget(content, maxTokens);

	return {
		type: "pull",
		owner,
		repo,
		number: prNumber,
		title: `PR #${prNumber}: ${pr.title}`,
		content: budget.content,
		url: `https://github.com/${owner}/${repo}/pull/${prNumber}`,
		metadata: { state: pr.state, additions: pr.additions, deletions: pr.deletions, truncated: budget.truncated },
	};
}

async function fetchWiki(
	owner: string, repo: string,
	page?: string, maxTokens: *** = 5000,
): Promise<GitHubContent> {
	// GitHub wikis are Git repos at wiki URLs
	const wikiPage = page ?? "Home";
	const rawUrl = `https://raw.githubusercontent.com/wiki/${owner}/${repo}/${wikiPage}.md`;
	const res = await fetch(rawUrl, {
		signal: AbortSignal.timeout(10000),
		headers: { "User-Agent": "Pi-Web-Research/1.0" },
	});
	if (!res.ok) throw new Error(`Wiki fetch error: ${res.status}`);
	const content = await res.text();
	const budget = enforceBudget(content, maxTokens);

	return {
		type: "wiki",
		owner,
		repo,
		path: wikiPage,
		title: `${owner}/${repo} Wiki: ${wikiPage}`,
		content: budget.content,
		url: `https://github.com/${owner}/${repo}/wiki/${wikiPage}`,
		metadata: { truncated: budget.truncated },
	};
}

import type { BudgetResult } from "../types.ts";

/** Approximate chars per token (conservative for mixed English/code). */
const CHARS_PER_TOKEN = ***;

/**
 * Estimate the number of tokens in a string.
 * Uses the ~4 chars/token approximation.
 */
export function estimateTokens(text: string): number {
	return Math.ceil(text.length / CHARS_PER_TOKEN);
}

/**
 * Enforce a token budget by truncating content if necessary.
 * Returns the content (possibly truncated) plus metadata.
 */
export function enforceBudget(content: string, maxTokens: *** BudgetResult {
	const originalLength = content.length;
	const originalTokens = ***;

	if (originalTokens <= maxTokens) {
		return {
			content,
			truncated: false,
			originalLength,
			finalLength: originalLength,
			originalTokens,
			finalTokens: ***,
		};
	}

	// Truncate at character boundary
	const maxChars = maxTokens * CHARS_PER_TOKEN;
	let truncated = content.slice(0, maxChars);

	// Don't cut in the middle of a line if possible
	const lastNewline = truncated.lastIndexOf("\n");
	if (lastNewline > maxChars * 0.8) {
		truncated = truncated.slice(0, lastNewline);
	}

	const truncationNotice = `\n\n[... content truncated at ~${maxChars} chars (≈${maxTokens} tokens) ...]`;
	truncated += truncationNotice;

	const finalTokens = ***;

	return {
		content: truncated,
		truncated: true,
		originalLength,
		finalLength: truncated.length,
		originalTokens,
		finalTokens,
	};
}

import Database from "better-sqlite3";
import * as fs from "node:fs";
import * as path from "node:path";
import type { CacheEntry } from "../types.ts";

/**
 * SQLite-based content cache for fetched URLs.
 * Stored at `.pi/web-research-cache/cache.db`.
 */
export class CacheStore {
	private db!: Database.Database;
	private dbPath: string;
	private maxSizeBytes: number;
	private _isOpen = false;

	constructor(cwd: string, maxSizeMB: number = 50) {
		const cacheDir = path.join(cwd, ".pi", "web-research-cache");
		fs.mkdirSync(cacheDir, { recursive: true });
		this.dbPath = path.join(cacheDir, "cache.db");
		this.maxSizeBytes = maxSizeMB * 1024 * 1024;
	}

	open(): void {
		if (this._isOpen) return;
		this.db = new Database(this.dbPath);
		this.db.pragma("journal_mode = WAL");
		this.db.exec(`
			CREATE TABLE IF NOT EXISTS cache_entries (
				url TEXT PRIMARY KEY,
				content TEXT NOT NULL,
				content_type TEXT NOT NULL,
				fetched_at INTEGER NOT NULL,
				expires_at INTEGER NOT NULL,
				size_bytes INTEGER NOT NULL
			)
		`);
		this._isOpen = true;
	}

	close(): void {
		if (!this._isOpen) return;
		this.db.close();
		this._isOpen = false;
	}

	get isOpen(): boolean {
		return this._isOpen;
	}

	/** Get a cached entry by URL. Returns null if not found or expired. */
	get(url: string): CacheEntry | null {
		this.ensureOpen();
		const now = Date.now();
		const row = this.db.prepare(
			"SELECT * FROM cache_entries WHERE url = ? AND expires_at > ?",
		).get(url, now) as CacheEntry | undefined;
		return row ?? null;
	}

	/** Store content in the cache. */
	set(url: string, content: string, contentType: string, ttlMs: number): void {
		this.ensureOpen();
		const now = Date.now();
		const sizeBytes = Buffer.byteLength(content, "utf-8");
		this.db.prepare(
			`INSERT OR REPLACE INTO cache_entries (url, content, content_type, fetched_at, expires_at, size_bytes)
			 VALUES (?, ?, ?, ?, ?, ?)`,
		).run(url, content, contentType, now, now + ttlMs, sizeBytes);
	}

	/** Clear all cached entries. */
	clear(): number {
		this.ensureOpen();
		const result = this.db.prepare("DELETE FROM cache_entries").run();
		return result.changes;
	}

	/** Remove expired entries. Returns count of removed entries. */
	cleanExpired(): number {
		this.ensureOpen();
		const now = Date.now();
		const result = this.db.prepare("DELETE FROM cache_entries WHERE expires_at <= ?").run(now);
		return result.changes;
	}

	/** Get total cache size in bytes. */
	getSizeBytes(): number {
		this.ensureOpen();
		const row = this.db.prepare("SELECT COALESCE(SUM(size_bytes), 0) as total FROM cache_entries").get() as { total: number };
		return row.total;
	}

	/** Get count of cached entries. */
	getCount(): number {
		this.ensureOpen();
		const row = this.db.prepare("SELECT COUNT(*) as count FROM cache_entries").get() as { count: number };
		return row.count;
	}

	/** Evict oldest entries if cache exceeds max size. */
	evictIfNeeded(): number {
		this.ensureOpen();
		const currentSize = this.getSizeBytes();
		if (currentSize <= this.maxSizeBytes) return 0;

		let evicted = 0;
		// Delete oldest entries until under the limit
		const rows = this.db.prepare(
			"SELECT url, size_bytes FROM cache_entries ORDER BY fetched_at ASC",
		).all() as Array<{ url: string; size_bytes: number }>;

		let size = currentSize;
		const del = this.db.prepare("DELETE FROM cache_entries WHERE url = ?");
		for (const row of rows) {
			if (size <= this.maxSizeBytes * 0.8) break; // Evict to 80% of max
			del.run(row.url);
			size -= row.size_bytes;
			evicted++;
		}
		return evicted;
	}

	private ensureOpen(): void {
		if (!this._isOpen) throw new Error("CacheStore is not open. Call open() first.");
	}
}

/** Tracking/query parameters to strip during URL normalization. */
const TRACKING_PARAMS = new Set([
	"utm_source", "utm_medium", "utm_campaign", "utm_term", "utm_content",
	"fbclid", "gclid", "gclsrc", "dclid", "msclkid",
	"mc_eid", "mc_cid", "_ga", "_gl", "_hsenc", "_hsmi",
	"hsCtaTracking", "vero_id", "oly_anon_id", "oly_enc_id",
	"ref", "referrer", "source", "s_cid",
]);

/**
 * Normalize a URL for deduplication purposes:
 * - Lowercase scheme and host
 * - Strip trailing slash from path
 * - Sort query parameters alphabetically
 * - Strip tracking parameters
 * - Strip hash/fragment
 */
export function normalizeUrl(url: string): string {
	try {
		const parsed = new URL(url);

		// Lowercase host
		parsed.hostname = parsed.hostname.toLowerCase();

		// Strip fragment
		parsed.hash = "";

		// Strip trailing slash from path (unless root)
		if (parsed.pathname.length > 1 && parsed.pathname.endsWith("/")) {
			parsed.pathname = parsed.pathname.slice(0, -1);
		}

		// Filter and sort query params
		const params = new URLSearchParams();
		const entries = [...parsed.searchParams.entries()]
			.filter(([key]) => !TRACKING_PARAMS.has(key.toLowerCase()))
			.sort(([a], [b]) => a.localeCompare(b));

		for (const [key, value] of entries) {
			params.append(key, value);
		}
		parsed.search = params.toString();

		return parsed.toString();
	} catch {
		// If URL parsing fails, return as-is
		return url;
	}
}

/**
 * Check if two URLs are equivalent after normalization.
 */
export function urlsMatch(urlA: string, urlB: string): boolean {
	return normalizeUrl(urlA) === normalizeUrl(urlB);
}

/**
 * Deduplicate an array of URLs, returning only unique normalized URLs
 * while preserving the original URL forms from the first occurrence.
 */
export function dedupUrls(urls: string[]): string[] {
	const seen = new Set<string>();
	const result: string[] = [];
	for (const url of urls) {
		const normalized = normalizeUrl(url);
		if (!seen.has(normalized)) {
			seen.add(normalized);
			result.push(url);
		}
	}
	return result;
}

/**
 * Given an array of search results, deduplicate by normalized URL.
 * Keeps the first occurrence when URLs normalize to the same value.
 */
export function dedupSearchResults<T extends { url: string }>(results: T[]): T[] {
	const seen = new Set<string>();
	return results.filter((r) => {
		const normalized = normalizeUrl(r.url);
		if (seen.has(normalized)) return false;
		seen.add(normalized);
		return true;
	});
}

import type { SearchResult, ExtractedContent, ResearchReport, WebResearchConfig } from "../types.ts";
import { fallbackSearch, type FallbackChainConfig, type FallbackFailure } from "../search/fallback-chain.ts";
import { createEngine } from "../search/fallback-chain.ts";
import type { SearchEngine } from "../search/engine.ts";
import { fetchUrl } from "../extract/fetcher.ts";
import { extractContent } from "../extract/extractor.ts";
import { parseGitHubUrl, extractGitHub } from "../extract/github.ts";
import { enforceBudget } from "../extract/budget.ts";
import { synthesize, type SourceContent } from "./synthesize.ts";
import { formatReport } from "./report.ts";
import { dedupSearchResults } from "../cache/dedup.ts";
import type { CacheStore } from "../cache/store.ts";

/** Research depth → number of sources to fetch. */
const DEPTH_SOURCE_MAP = {
	quick: 3,
	standard: 5,
	deep: 8,
} as const;

/** Research depth → max tokens per source. */
const DEPTH_TOKEN_MAP = *** 2000,
	standard: 3000,
	deep: 5000,
} as const;

/**
 * Execute a full research cycle:
 * 1. Search across multiple engines
 * 2. Fetch and extract top results
 * 3. Synthesize findings into a report
 */
export async function executeResearch(
	query: string,
	depth: "quick" | "standard" | "deep" = "standard",
	maxSources: number = DEPTH_SOURCE_MAP[depth],
	config: WebResearchConfig,
	cache?: CacheStore,
): Promise<ResearchReport> {
	const sourceLimit = Math.min(maxSources, DEPTH_SOURCE_MAP[depth]);
	const tokensPerSource = ***;

	// Step 1: Search
	const chainConfig: FallbackChainConfig = {
		chain: config.search.fallbackChain,
		apiKeys: ***,
	};

	let searchResults: SearchResult[];
	const searchOutcome = await fallbackSearch(chainConfig, query, {
		maxResults: sourceLimit * 2, // Over-fetch for dedup
	});

	if ("suggestion" in searchOutcome && "triedEngines" in searchOutcome) {
		searchResults = (searchOutcome as FallbackFailure).results;
	} else {
		searchResults = searchOutcome as SearchResult[];
	}

	// Dedup
	searchResults = dedupSearchResults(searchResults).slice(0, sourceLimit);

	// Step 2: Fetch + Extract
	const sourceContents: SourceContent[] = [];
	for (const result of searchResults) {
		if (!result.url) continue;

		try {
			const content = await fetchAndExtract(result, tokensPerSource, config, cache);
			if (content) {
				sourceContents.push({
					url: result.url,
					title: result.title,
					snippet: result.snippet,
					content: content.content,
				});
			}
		} catch {
			// Skip failed fetches
		}
	}

	// Step 3: Synthesize
	const synthesized = synthesize(query, sourceContents);

	// Step 4: Format report
	return formatReport({
		query,
		depth,
		summary: synthesized.summary,
		findings: synthesized.findings,
		contradictions: synthesized.contradictions,
		recommendations: synthesized.recommendations,
		sources: searchResults.map((r) => ({
			title: r.title,
			url: r.url,
			snippet: r.snippet,
			retrievedAt: new Date().toISOString(),
		})),
	});
}

async function fetchAndExtract(
	result: SearchResult,
	maxTokens: ***,
	config: WebResearchConfig,
	cache?: CacheStore,
): Promise<ExtractedContent | null> {
	// Check cache first
	if (cache?.isOpen) {
		const cached = cache.get(result.url);
		if (cached) {
			const budget = enforceBudget(cached.content, maxTokens);
			return {
				title: result.title,
				url: result.url,
				content: budget.content,
				contentType: "text",
				contentLength: budget.finalLength,
				truncated: budget.truncated,
			};
		}
	}

	// Check if GitHub URL
	const ghParsed = parseGitHubUrl(result.url);
	if (ghParsed) {
		try {
			const ghContent = await extractGitHub(result.url, { maxTokens });
			// Cache the result
			if (cache?.isOpen) {
				const ttl = config.cache.maxAgeHours * 60 * 60 * 1000;
				cache.set(result.url, ghContent.content, "text/plain", ttl);
			}
			return {
				title: ghContent.title,
				url: ghContent.url,
				content: ghContent.content,
				contentType: "text",
				contentLength: ghContent.content.length,
				truncated: (ghContent.metadata?.truncated as boolean) ?? false,
			};
		} catch {
			return null;
		}
	}

	// Regular URL fetch
	try {
		const fetched = await fetchUrl(result.url, config);
		const extracted = extractContent(fetched.content, fetched.url, {
			maxTokens,
			format: "text",
		});

		// Cache raw fetched content
		if (cache?.isOpen && config.cache.enabled) {
			const ttl = config.cache.maxAgeHours * 60 * 60 * 1000;
			cache.set(result.url, fetched.content, fetched.contentType, ttl);
		}

		return extracted;
	} catch {
		return null;
	}
}

/** A fetched source with its extracted content. */
export interface SourceContent {
	url: string;
	title: string;
	snippet: string;
	content: string;
}

/** Synthesized research finding. */
export interface SynthFinding {
	topic: string;
	content: string;
	sources: string[];
	confidence: "high" | "medium" | "low";
}

/** Result of synthesizing multiple sources. */
export interface SynthesisResult {
	summary: string;
	findings: SynthFinding[];
	contradictions: string[];
	recommendations: string[];
}

/**
 * Synthesize findings from multiple sources.
 * This is a text-based heuristic synthesis (not LLM-based) that:
 * - Identifies key topics across sources
 * - Groups information by topic
 * - Detects contradictions
 * - Generates recommendations based on source agreement
 */
export function synthesize(query: string, sources: SourceContent[]): SynthesisResult {
	if (sources.length === 0) {
		return {
			summary: `No sources found for query: "${query}"`,
			findings: [],
			contradictions: [],
			recommendations: [],
		};
	}

	// Extract key sentences from each source
	const allSentences = extractKeySentences(sources);

	// Group by overlapping topics (keyword-based clustering)
	const findings = clusterIntoFindings(allSentences, query);

	// Detect contradictions (simple heuristic: opposing language)
	const contradictions = detectContradictions(allSentences);

	// Generate recommendations
	const recommendations = generateRecommendations(findings, sources.length);

	// Generate summary
	const summary = generateSummary(query, findings, sources.length);

	return { summary, findings, contradictions, recommendations };
}

interface TaggedSentence {
	text: string;
	url: string;
	title: string;
	words: Set<string>;
}

function extractKeySentences(sources: SourceContent[]): TaggedSentence[] {
	const sentences: TaggedSentence[] = [];

	for (const source of sources) {
		const lines = source.content.split(/[.!?\n]/).filter((l) => l.trim().length > 20);
		for (const line of lines) {
			const trimmed = line.trim();
			const words = new Set(
				trimmed.toLowerCase().split(/\s+/).filter((w) => w.length > 3),
			);
			sentences.push({
				text: trimmed,
				url: source.url,
				title: source.title,
				words,
			});
		}
	}

	return sentences;
}

function clusterIntoFindings(
	sentences: TaggedSentence[],
	query: string,
): SynthFinding[] {
	if (sentences.length === 0) return [];

	// Simple keyword overlap clustering
	const queryWords = new Set(query.toLowerCase().split(/\s+/));
	const clusters: Array<{ sentences: TaggedSentence[]; topic: string }> = [];
	const used = new Set<number>();

	// Take representative sentences (max 10 findings)
	const step = Math.max(1, Math.floor(sentences.length / 10));
	for (let i = 0; i < sentences.length && clusters.length < 10; i += step) {
		if (used.has(i)) continue;
		const s = sentences[i];
		const cluster: TaggedSentence[] = [s];
		used.add(i);

		// Find overlapping sentences
		for (let j = i + 1; j < sentences.length && cluster.length < 5; j++) {
			if (used.has(j)) continue;
			const overlap = setOverlap(s.words, sentences[j].words);
			if (overlap > 0.3) {
				cluster.push(sentences[j]);
				used.add(j);
			}
		}

		// Derive topic from most common meaningful words
		const topic = deriveTopic(cluster, queryWords);
		clusters.push({ sentences: cluster, topic });
	}

	return clusters.map((c) => ({
		topic: c.topic,
		content: c.sentences.map((s) => s.text).join(". "),
		sources: [...new Set(c.sentences.map((s) => s.url))],
		confidence: determineConfidence(c.sentences),
	}));
}

function setOverlap(a: Set<string>, b: Set<string>): number {
	if (a.size === 0 || b.size === 0) return 0;
	let overlap = 0;
	for (const word of a) {
		if (b.has(word)) overlap++;
	}
	return overlap / Math.min(a.size, b.size);
}

function deriveTopic(sentences: TaggedSentence[], queryWords: Set<string>): string {
	// Find most common non-query words
	const wordFreq = new Map<string, number>();
	for (const s of sentences) {
		for (const w of s.words) {
			if (!queryWords.has(w) && w.length > 3) {
				wordFreq.set(w, (wordFreq.get(w) ?? 0) + 1);
			}
		}
	}
	const top = [...wordFreq.entries()]
		.sort((a, b) => b[1] - a[1])
		.slice(0, 3)
		.map(([w]) => w);
	return top.length > 0 ? top.join(" / ") : "General";
}

function determineConfidence(sentences: TaggedSentence[]): "high" | "medium" | "low" {
	const uniqueSources = new Set(sentences.map((s) => s.url)).size;
	if (uniqueSources >= 3) return "high";
	if (uniqueSources >= 2) return "medium";
	return "low";
}

const CONTRADICTION_PAIRS: Array<[string, string]> = [
	["not", "is"],
	["don't", "do"],
	["cannot", "can"],
	["should not", "should"],
	["never", "always"],
	["no", "yes"],
	["avoid", "recommend"],
	["deprecated", "recommended"],
];

function detectContradictions(sentences: TaggedSentence[]): string[] {
	const contradictions: string[] = [];
	const byTopic = new Map<string, TaggedSentence[]>();

	// Group sentences that share significant word overlap
	for (const s of sentences) {
		let matched = false;
		for (const [, group] of byTopic) {
			if (group.length > 0 && setOverlap(s.words, group[0].words) > 0.3) {
				group.push(s);
				matched = true;
				break;
			}
		}
		if (!matched) {
			byTopic.set(s.text.slice(0, 50), [s]);
		}
	}

	// Check for contradictory pairs within groups
	for (const [, group] of byTopic) {
		if (group.length < 2) continue;
		for (let i = 0; i < group.length; i++) {
			for (let j = i + 1; j < group.length; j++) {
				const textA = group[i].text.toLowerCase();
				const textB = group[j].text.toLowerCase();
				for (const [neg, pos] of CONTRADICTION_PAIRS) {
					if (
						(textA.includes(neg) && textB.includes(pos)) ||
						(textA.includes(pos) && textB.includes(neg))
					) {
						contradictions.push(
							`Source disagreement: "${group[i].text.slice(0, 80)}..." vs "${group[j].text.slice(0, 80)}..."`,
						);
						break;
					}
				}
			}
		}
	}

	return contradictions.slice(0, 5); // Cap at 5
}

function generateRecommendations(
	findings: SynthFinding[],
	sourceCount: number,
): string[] {
	const recs: string[] = [];

	if (sourceCount === 0) {
		recs.push("No sources were found. Try a different query or check API keys.");
		return recs;
	}

	if (sourceCount === 1) {
		recs.push("Only one source was found. Cross-reference with additional searches for reliability.");
	}

	const lowConfidence = findings.filter((f) => f.confidence === "low");
	if (lowConfidence.length > 0) {
		recs.push(`${lowConfidence.length} finding(s) have low confidence. Verify with additional sources.`);
	}

	if (findings.length > 0) {
		const highConf = findings.filter((f) => f.confidence === "high");
		if (highConf.length > 0) {
			recs.push(`Strong consensus on ${highConf.length} topic(s): ${highConf.map((f) => f.topic).join(", ")}.`);
		}
	}

	if (recs.length === 0) {
		recs.push("Research complete. Review findings for actionable insights.");
	}

	return recs;
}

function generateSummary(query: string, findings: SynthFinding[], sourceCount: number): string {
	const topics = findings.slice(0, 3).map((f) => f.topic).join(", ");
	return `Research on "${query}" analyzed ${sourceCount} source(s) and identified ${findings.length} topic(s)${topics ? ` including: ${topics}` : ""}.`;
}

import type { ResearchReport, ResearchFinding, ResearchSource } from "../types.ts";

/** Options for formatting a research report. */
export interface ReportOptions {
	query: string;
	depth: "quick" | "standard" | "deep";
	summary: string;
	findings: ResearchFinding[];
	contradictions: string[];
	recommendations: string[];
	sources: ResearchSource[];
}

/**
 * Format a research report as a structured text document.
 */
export function formatReport(opts: ReportOptions): ResearchReport {
	const report: ResearchReport = {
		query: opts.query,
		depth: opts.depth,
		summary: opts.summary,
		findings: opts.findings,
		contradictions: opts.contradictions,
		recommendations: opts.recommendations,
		sources: opts.sources,
		generatedAt: new Date().toISOString(),
	};

	return report;
}

/**
 * Render a ResearchReport as human-readable text.
 */
export function renderReport(report: ResearchReport): string {
	const lines: string[] = [];

	lines.push(`# Research Report: ${report.query}`);
	lines.push(`**Depth:** ${report.depth} | **Generated:** ${report.generatedAt}`);
	lines.push(`**Sources:** ${report.sources.length}`);
	lines.push("");

	// Summary
	lines.push("## Summary");
	lines.push(report.summary);
	lines.push("");

	// Findings
	if (report.findings.length > 0) {
		lines.push("## Findings");
		for (let i = 0; i < report.findings.length; i++) {
			const f = report.findings[i];
			if (!f) continue;
			const confidence = f.confidence === "high" ? "🟢" : f.confidence === "medium" ? "🟡" : "🔴";
			lines.push(`### ${i + 1}. ${f.topic} ${confidence}`);
			lines.push(f.content);
			if (f.sources.length > 0) {
				lines.push(`_Sources: ${f.sources.join(", ")}_`);
			}
			lines.push("");
		}
	}

	// Contradictions
	if (report.contradictions.length > 0) {
		lines.push("## ⚠️ Contradictions");
		for (const c of report.contradictions) {
			lines.push(`- ${c}`);
		}
		lines.push("");
	}

	// Recommendations
	if (report.recommendations.length > 0) {
		lines.push("## Recommendations");
		for (const r of report.recommendations) {
			lines.push(`- ${r}`);
		}
		lines.push("");
	}

	// Sources
	if (report.sources.length > 0) {
		lines.push("## Sources");
		for (const s of report.sources) {
			lines.push(`- [${s.title}](${s.url}) — ${s.snippet.slice(0, 100)}`);
		}
		lines.push("");
	}

	return lines.join("\n");
}

/**
 * Render a ResearchReport as JSON (compact).
 */
export function renderReportJson(report: ResearchReport): string {
	return JSON.stringify(report, null, 2);
}

import type { WebResearchConfig, SearchResult, SearchOptions } from "../types.ts";
import { fallbackSearch, createEngine, type FallbackChainConfig, type FallbackFailure } from "../search/fallback-chain.ts";
import type { SearchEngine } from "../search/engine.ts";
import { dedupSearchResults } from "../cache/dedup.ts";

export interface WebSearchInput {
	query: string;
	maxResults?: number;
	engine?: "auto" | "brave" | "gemini" | "exa" | "duckduckgo";
	recency?: "day" | "week" | "month" | "year" | "all";
}

export interface WebSearchOutput {
	results: SearchResult[];
	engine?: string;
	error?: string;
}

export async function handleWebSearch(
	input: WebSearchInput,
	config: WebResearchConfig,
): Promise<WebSearchOutput> {
	const opts: SearchOptions = {
		maxResults: input.maxResults ?? config.search.maxResults,
		recency: input.recency,
	};

	// Single engine mode
	if (input.engine && input.engine !== "auto") {
		try {
			const engine: SearchEngine = createEngine(input.engine, {
				brave: config.apiKeys.brave,
				gemini: config.apiKeys.gemini,
				exa: config.apiKeys.exa,
			});

			if (!engine.isAvailable()) {
				return {
					results: [],
					engine: input.engine,
					error: `Engine "${input.engine}" is not available (missing API key or credentials).`,
				};
			}

			const results = await engine.search(input.query, opts);
			return {
				results: dedupSearchResults(results),
				engine: engine.name,
			};
		} catch (err) {
			return {
				results: [],
				engine: input.engine,
				error: `Search failed: ${err instanceof Error ? err.message : String(err)}`,
			};
		}
	}

	// Auto / fallback mode
	const chainConfig: FallbackChainConfig = {
		chain: config.search.fallbackChain,
		apiKeys: ***
			brave: config.apiKeys.brave,
			gemini: config.apiKeys.gemini,
			exa: config.apiKeys.exa,
		},
	};

	const outcome = await fallbackSearch(chainConfig, input.query, opts);

	if ("suggestion" in outcome && "triedEngines" in outcome) {
		const failure = outcome as FallbackFailure;
		return {
			results: failure.results,
			error: failure.suggestion,
		};
	}

	return {
		results: dedupSearchResults(outcome as SearchResult[]),
	};
}

import type { WebResearchConfig, ExtractedContent, ExtractOptions } from "../types.ts";
import { fetchUrl } from "../extract/fetcher.ts";
import { extractContent } from "../extract/extractor.ts";
import { parseGitHubUrl, extractGitHub } from "../extract/github.ts";
import { enforceBudget } from "../extract/budget.ts";
import type { CacheStore } from "../cache/store.ts";

export interface WebFetchInput {
	url: string;
	maxTokens?: number;
	extract?: "text" | "html" | "markdown";
	selector?: string;
}

export interface WebFetchOutput {
	title: string;
	url: string;
	content: string;
	contentType: string;
	contentLength: number;
	truncated: boolean;
	fromCache: boolean;
	error?: string;
}

export async function handleWebFetch(
	input: WebFetchInput,
	config: WebResearchConfig,
	cache?: CacheStore,
): Promise<WebFetchOutput> {
	const url = input.url;
	const maxTokens = *** ?? config.fetch.maxTokens;
	const format = input.extract ?? "text";

	// Check cache first
	if (cache?.isOpen && config.cache.enabled) {
		const cached = cache.get(url);
		if (cached) {
			const budget = enforceBudget(cached.content, maxTokens);
			return {
				title: url,
				url,
				content: budget.content,
				contentType: format,
				contentLength: budget.finalLength,
				truncated: budget.truncated,
				fromCache: true,
			};
		}
	}

	// GitHub special handling
	const ghParsed = parseGitHubUrl(url);
	if (ghParsed) {
		try {
			const ghContent = await extractGitHub(url, { maxTokens, format });
			if (cache?.isOpen && config.cache.enabled) {
				const ttl = config.cache.maxAgeHours * 60 * 60 * 1000;
				cache.set(url, ghContent.content, "text/plain", ttl);
			}
			return {
				title: ghContent.title,
				url: ghContent.url,
				content: ghContent.content,
				contentType: format,
				contentLength: ghContent.content.length,
				truncated: (ghContent.metadata?.truncated as boolean) ?? false,
				fromCache: false,
			};
		} catch (err) {
			return {
				title: url,
				url,
				content: "",
				contentType: format,
				contentLength: 0,
				truncated: false,
				fromCache: false,
				error: `GitHub extraction failed: ${err instanceof Error ? err.message : String(err)}`,
			};
		}
	}

	// Regular fetch
	try {
		const fetched = await fetchUrl(url, config);
		const extracted = extractContent(fetched.content, fetched.url, {
			maxTokens,
			format,
			selector: input.selector,
		});

		// Cache the raw fetched content
		if (cache?.isOpen && config.cache.enabled) {
			const ttl = config.cache.maxAgeHours * 60 * 60 * 1000;
			cache.set(url, fetched.content, fetched.contentType, ttl);
		}

		return {
			title: extracted.title,
			url: extracted.url,
			content: extracted.content,
			contentType: extracted.contentType,
			contentLength: extracted.contentLength,
			truncated: extracted.truncated,
			fromCache: false,
		};
	} catch (err) {
		return {
			title: url,
			url,
			content: "",
			contentType: format,
			contentLength: 0,
			truncated: false,
			fromCache: false,
			error: `Fetch failed: ${err instanceof Error ? err.message : String(err)}`,
		};
	}
}

import type { WebResearchConfig, ResearchReport } from "../types.ts";
import { executeResearch } from "../research/mode.ts";
import { renderReport, renderReportJson } from "../research/report.ts";
import type { CacheStore } from "../cache/store.ts";

export interface WebResearchInput {
	query: string;
	depth?: "quick" | "standard" | "deep";
	maxSources?: number;
	format?: "text" | "json";
}

export interface WebResearchOutput {
	report: ResearchReport;
	text: string;
	error?: string;
}

export async function handleWebResearch(
	input: WebResearchInput,
	config: WebResearchConfig,
	cache?: CacheStore,
): Promise<WebResearchOutput> {
	try {
		const report = await executeResearch(
			input.query,
			input.depth ?? "standard",
			input.maxSources,
			config,
			cache,
		);

		const text = input.format === "json"
			? renderReportJson(report)
			: renderReport(report);

		return { report, text };
	} catch (err) {
		const emptyReport: ResearchReport = {
			query: input.query,
			depth: input.depth ?? "standard",
			summary: "Research failed.",
			findings: [],
			contradictions: [],
			recommendations: [],
			sources: [],
			generatedAt: new Date().toISOString(),
		};
		return {
			report: emptyReport,
			text: `Research failed: ${err instanceof Error ? err.message : String(err)}`,
			error: err instanceof Error ? err.message : String(err),
		};
	}
}

import type { ExtensionAPI, ExtensionContext, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { loadConfig } from "../config.ts";
import { handleWebSearch, type WebSearchInput } from "../tools/web_search.ts";
import { handleWebFetch, type WebFetchInput } from "../tools/web_fetch.ts";
import { handleWebResearch, type WebResearchInput } from "../tools/web_research.ts";
import { CacheStore } from "../cache/store.ts";

let currentCtx: ExtensionContext | undefined;
let cacheStore: CacheStore | undefined;

function getCache(cwd: string, config: ReturnType<typeof loadConfig>): CacheStore {
	if (cacheStore && cacheStore.isOpen) return cacheStore;
	cacheStore?.close();
	cacheStore = new CacheStore(cwd, config.cache.maxSizeMB);
	cacheStore.open();
	return cacheStore;
}

const toolResult = (text: string) =>
	({ content: [{ type: "text" as const, text }], details: {} });

export function registerPiWebResearch(pi: ExtensionAPI): void {
	// ── session_start ─────────────────────────────────────────────────────────
	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const config = loadConfig(ctx.cwd);
		if (!config.enabled) return;

		// Initialize cache
		if (config.cache.enabled) {
			try {
				const cache = getCache(ctx.cwd, config);
				cache.cleanExpired();
				cache.evictIfNeeded();
			} catch { /* non-critical */ }
		}
	});

	// ── session_shutdown ───────────────────────────────────────────────────────
	pi.on("session_shutdown", () => {
		cacheStore?.close();
		cacheStore = undefined;
		currentCtx = undefined;
	});

	// ── Register tools ─────────────────────────────────────────────────────────

	const webSearchTool: ToolDefinition = {
		name: "web_search",
		label: "Web Search",
		description: "Search the web using Brave, Gemini, Exa, or DuckDuckGo. Falls back automatically if a provider is unavailable.",
		parameters: Type.Object({
			query: Type.String({ description: "Search query" }),
			maxResults: Type.Optional(Type.Number({ description: "Maximum results to return (default: 5)" })),
			engine: Type.Optional(Type.String({ description: 'Engine: "auto" | "brave" | "gemini" | "exa" | "duckduckgo"' })),
			recency: Type.Optional(Type.String({ description: 'Recency filter: "day" | "week" | "month" | "year" | "all"' })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const config = loadConfig(cwd);
			const result = await handleWebSearch(params as unknown as WebSearchInput, config);
			if (result.error) {
				return toolResult(`Search completed with issues: ${result.error}\n\nResults: ${JSON.stringify(result.results, null, 2)}`);
			}
			return toolResult(JSON.stringify(result.results, null, 2));
		},
	};

	const webFetchTool: ToolDefinition = {
		name: "web_fetch",
		label: "Web Fetch",
		description: "Fetch and extract content from a URL. Supports text, HTML, and markdown extraction with token budget enforcement.",
		parameters: Type.Object({
			url: Type.String({ description: "URL to fetch" }),
			maxTokens: *** description: "Maximum tokens in response (default: 5000)" })),
			extract: Type.Optional(Type.String({ description: 'Extraction format: "text" | "html" | "markdown"' })),
			selector: Type.Optional(Type.String({ description: "CSS selector for targeted extraction" })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const config = loadConfig(cwd);
			const cache = config.cache.enabled ? getCache(cwd, config) : undefined;
			const result = await handleWebFetch(params as unknown as WebFetchInput, config, cache);
			if (result.error) {
				return toolResult(`Fetch failed: ${result.error}`);
			}
			const header = `# ${result.title}\nURL: ${result.url}${result.truncated ? " [TRUNCATED]" : ""}${result.fromCache ? " [FROM CACHE]" : ""}\n\n`;
			return toolResult(header + result.content);
		},
	};

	const webResearchTool: ToolDefinition = {
		name: "web_research",
		label: "Web Research",
		description: "Deep research mode: search, fetch, extract, and synthesize information from multiple sources into a comprehensive report.",
		parameters: Type.Object({
			query: Type.String({ description: "Research query" }),
			depth: Type.Optional(Type.String({ description: 'Research depth: "quick" | "standard" | "deep"' })),
			maxSources: Type.Optional(Type.Number({ description: "Maximum sources to analyze (default: varies by depth)" })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const config = loadConfig(cwd);
			const cache = config.cache.enabled ? getCache(cwd, config) : undefined;
			const result = await handleWebResearch(params as unknown as WebResearchInput, config, cache);
			if (result.error) {
				return toolResult(`Research encountered errors: ${result.error}\n\n${result.text}`);
			}
			return toolResult(result.text);
		},
	};

	for (const tool of [webSearchTool, webFetchTool, webResearchTool]) {
		try {
			pi.registerTool(tool);
		} catch { /* tool registration may not be available */ }
	}

	// ── Register commands ──────────────────────────────────────────────────────

	try {
		pi.registerCommand({
			name: "research",
			description: "Start interactive research mode on a topic",
			async handler(args) {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const config = loadConfig(cwd);
				const cache = config.cache.enabled ? getCache(cwd, config) : undefined;
				const query = args?._?.join(" ") ?? args?.query ?? "";
				if (!query) return "Usage: /research <query>";
				const result = await handleWebResearch({ query, depth: "standard" }, config, cache);
				return result.text;
			},
		});
	} catch { /* command registration may not be available */ }

	try {
		pi.registerCommand({
			name: "web",
			description: "Web research commands: search, cache clear",
			async handler(args) {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const config = loadConfig(cwd);

				const subcommand = args?._?.[0] ?? "";
				if (subcommand === "cache") {
					const action = args?._?.[1] ?? "";
					if (action === "clear") {
						if (!cacheStore?.isOpen) return "Cache not initialized.";
						const cleared = cacheStore.clear();
						return `Cleared ${cleared} cached entries.`;
					}
					return "Usage: /web cache clear";
				}

				if (subcommand === "search") {
					const query = args?._?.slice(1).join(" ") ?? "";
					if (!query) return "Usage: /web search <query>";
					const result = await handleWebSearch({ query }, config);
					if (result.error) return `Search error: ${result.error}`;
					return result.results.map((r, i) =>
						`${i + 1}. **${r.title}**\n   ${r.url}\n   ${r.snippet}`,
					).join("\n\n");
				}

				return "Usage: /web <search|cache> [args]";
			},
		});
	} catch { /* command registration may not be available */ }
}

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { enforceBudget, estimateTokens } from "../../src/extract/budget.ts";

describe("estimateTokens", () => {
	it("returns 0 for empty string", () => {
		assert.equal(estimateTokens(""), 0);
	});

	it("approximates 4 chars per token", () => {
		assert.equal(estimateTokens("abcd"), 1);
		assert.equal(estimateTokens("abcdefgh"), 2);
	});

	it("rounds up", () => {
		assert.equal(estimateTokens("abc"), 1);
		assert.equal(estimateTokens("abcde"), 2);
	});
});

describe("enforceBudget", () => {
	it("does not truncate content within budget", () => {
		const result = enforceBudget("hello world", 100);
		assert.equal(result.truncated, false);
		assert.equal(result.content, "hello world");
		assert.equal(result.originalLength, 11);
		assert.equal(result.finalLength, 11);
	});

	it("truncates content exceeding budget", () => {
		const longContent = "a".repeat(1000);
		const result = enforceBudget(longContent, 10); // 10 tokens = *** chars
		assert.equal(result.truncated, true);
		assert.ok(result.content.length < longContent.length);
		assert.ok(result.content.includes("truncated"));
	});

	it("preserves content at exact budget boundary", () => {
		const content = "a".repeat(40); // 40 chars = 10 tokens
		const result = enforceBudget(content, 10);
		assert.equal(result.truncated, false);
	});

	it("truncates at newline boundary when possible", () => {
		const content = "a".repeat(80) + "\n" + "b".repeat(80);
		const result = enforceBudget(content, 10); // 40 chars
		// Should include the truncation notice
		assert.equal(result.truncated, true);
		assert.ok(result.content.includes("truncated"));
	});

	it("handles empty content", () => {
		const result = enforceBudget("", 100);
		assert.equal(result.truncated, false);
		assert.equal(result.content, "");
	});

	it("reports correct original and final lengths", () => {
		const content = "a".repeat(500);
		const result = enforceBudget(content, 10);
		assert.equal(result.originalLength, 500);
		assert.ok(result.finalLength < 500);
		assert.ok(result.finalLength > 0);
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { extractContent, htmlToMarkdown } from "../../src/extract/extractor.ts";

describe("extractContent", () => {
	it("extracts text from simple HTML", () => {
		const html = "<html><head><title>Test Page</title></head><body><p>Hello World</p></body></html>";
		const result = extractContent(html, "https://example.com");
		assert.equal(result.title, "Test Page");
		assert.ok(result.content.includes("Hello World"));
		assert.equal(result.contentType, "text");
		assert.equal(result.truncated, false);
	});

	it("removes script and style elements", () => {
		const html = `<html><body>
			<script>alert('xss')</script>
			<style>.foo { color: red; }</style>
			<p>Visible content</p>
		</body></html>`;
		const result = extractContent(html, "https://example.com");
		assert.ok(!result.content.includes("alert"));
		assert.ok(!result.content.includes("color: red"));
		assert.ok(result.content.includes("Visible content"));
	});

	it("respects CSS selector", () => {
		const html = `<html><body>
			<div class="sidebar">Sidebar noise</div>
			<article><p>Main article content</p></article>
		</body></html>`;
		const result = extractContent(html, "https://example.com", { selector: "article" });
		assert.ok(result.content.includes("Main article content"));
		assert.ok(!result.content.includes("Sidebar noise"));
	});

	it("extracts markdown format", () => {
		const html = `<html><body>
			<h1>Title</h1>
			<p>Paragraph with <strong>bold</strong> and <em>italic</em></p>
			<a href="https://example.com">Link</a>
		</body></html>`;
		const result = extractContent(html, "https://example.com", { format: "markdown" });
		assert.ok(result.content.includes("# Title"));
		assert.ok(result.content.includes("**bold**"));
		assert.ok(result.content.includes("*italic*"));
		assert.ok(result.content.includes("[Link](https://example.com)"));
	});

	it("prefers article element for main content", () => {
		const html = `<html><body>
			<nav>Nav content</nav>
			<article>
				${"Article content. ".repeat(20)}
			</article>
		</body></html>`;
		const result = extractContent(html, "https://example.com");
		assert.ok(result.content.includes("Article content"));
	});

	it("uses URL as fallback title", () => {
		const html = "<html><body><p>Content</p></body></html>";
		const result = extractContent(html, "https://example.com");
		assert.equal(result.title, "https://example.com");
	});

	it("enforces token budget", () => {
		const longText = "x".repeat(20000);
		const html = `<html><body><p>${longText}</p></body></html>`;
		const result = extractContent(html, "https://example.com", { maxTokens: *** });
		assert.equal(result.truncated, true);
		assert.ok(result.contentLength < longText.length);
	});
});

describe("htmlToMarkdown", () => {
	it("converts headings", () => {
		const html = "<h1>H1</h1><h2>H2</h2><h3>H3</h3>";
		const md = htmlToMarkdown(html);
		assert.ok(md.includes("# H1"));
		assert.ok(md.includes("## H2"));
		assert.ok(md.includes("### H3"));
	});

	it("converts links", () => {
		const html = '<a href="https://example.com">Click</a>';
		const md = htmlToMarkdown(html);
		assert.ok(md.includes("[Click](https://example.com)"));
	});

	it("converts bold and italic", () => {
		const md1 = htmlToMarkdown("<strong>bold</strong>");
		assert.ok(md1.includes("**bold**"));
		const md2 = htmlToMarkdown("<em>italic</em>");
		assert.ok(md2.includes("*italic*"));
	});

	it("converts code", () => {
		const md = htmlToMarkdown("<code>let x = 1</code>");
