		const result = parseGitHubUrl("https://github.com/owner/repo/blob/main/src/index.ts");
		assert.deepEqual(result, { type: "file", owner: "owner", repo: "repo", path: "src/index.ts" });
	});

	it("parses tree URL", () => {
		const result = parseGitHubUrl("https://github.com/owner/repo/tree/main/src");
		assert.deepEqual(result, { type: "tree", owner: "owner", repo: "repo", path: "src" });
	});

	it("parses issue URL", () => {
		const result = parseGitHubUrl("https://github.com/owner/repo/issues/42");
		assert.deepEqual(result, { type: "issue", owner: "owner", repo: "repo", number: 42 });
	});

	it("parses pull request URL", () => {
