		assert.deepEqual(result, { type: "wiki", owner: "owner", repo: "repo", path: undefined });
	});

	it("returns null for non-GitHub URLs", () => {
		assert.equal(parseGitHubUrl("https://example.com/page"), null);
	});

	it("returns null for GitHub URL with only owner", () => {
		assert.equal(parseGitHubUrl("https://github.com/owner"), null);
	});

