import { describe, it, beforeEach, afterEach } from "node:test";
import assert from "node:assert/strict";
import { CacheStore } from "../../src/cache/store.ts";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

function createTempDir(): string {
	return fs.mkdtempSync(path.join(os.tmpdir(), "pi-web-research-test-"));
}

describe("CacheStore", () => {
	let tmpDir: string;
	let store: CacheStore;

	beforeEach(() => {
		tmpDir = createTempDir();
		store = new CacheStore(tmpDir, 1); // 1MB max
		store.open();
	});

	afterEach(() => {
		store.close();
		fs.rmSync(tmpDir, { recursive: true, force: true });
	});

	it("stores and retrieves entries", () => {
		store.set("https://example.com", "Hello World", "text/html", 60000);
		const entry = store.get("https://example.com");
		assert.ok(entry);
		assert.equal(entry.url, "https://example.com");
		assert.equal(entry.content, "Hello World");
		assert.equal(entry.contentType, "text/html");
	});

	it("returns null for missing URLs", () => {
		assert.equal(store.get("https://missing.com"), null);
	});

	it("returns null for expired entries", () => {
		store.set("https://expired.com", "old content", "text/html", 1); // 1ms TTL
		// Wait for expiry
		const start = Date.now();
		while (Date.now() - start < 10) { /* busy wait */ }
		assert.equal(store.get("https://expired.com"), null);
	});

	it("overwrites existing entries", () => {
		store.set("https://example.com", "First", "text/html", 60000);
		store.set("https://example.com", "Second", "text/html", 60000);
		const entry = store.get("https://example.com");
		assert.ok(entry);
		assert.equal(entry.content, "Second");
	});

	it("clears all entries", () => {
		store.set("https://a.com", "A", "text/html", 60000);
		store.set("https://b.com", "B", "text/html", 60000);
		const cleared = store.clear();
		assert.equal(cleared, 2);
		assert.equal(store.get("https://a.com"), null);
		assert.equal(store.get("https://b.com"), null);
	});

	it("cleans expired entries", () => {
		store.set("https://expired.com", "old", "text/html", 1);
		store.set("https://fresh.com", "new", "text/html", 60000);
		const start = Date.now();
		while (Date.now() - start < 10) { /* busy wait */ }
		const removed = store.cleanExpired();
		assert.equal(removed, 1);
		assert.equal(store.get("https://expired.com"), null);
		assert.ok(store.get("https://fresh.com"));
	});

	it("reports correct size", () => {
		store.set("https://a.com", "A".repeat(100), "text/html", 60000);
		store.set("https://b.com", "B".repeat(100), "text/html", 60000);
		assert.ok(store.getSizeBytes() >= 200);
	});

	it("reports correct count", () => {
		store.set("https://a.com", "A", "text/html", 60000);
		store.set("https://b.com", "B", "text/html", 60000);
		assert.equal(store.getCount(), 2);
	});

	it("evicts entries when over max size", () => {
		// Max size is 1MB, insert enough to exceed it
		const largeContent = "X".repeat(200000);
		for (let i = 0; i < 10; i++) {
			store.set(`https://example.com/${i}`, largeContent, "text/html", 60000);
		}
		const evicted = store.evictIfNeeded();
		assert.ok(evicted > 0);
		assert.ok(store.getSizeBytes() < 1024 * 1024);
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { normalizeUrl, urlsMatch, dedupUrls, dedupSearchResults } from "../../src/cache/dedup.ts";

describe("normalizeUrl", () => {
	it("lowercases host", () => {
		assert.equal(
			normalizeUrl("https://Example.COM/page"),
			normalizeUrl("https://example.com/page"),
		);
	});

	it("strips trailing slash", () => {
		const result = normalizeUrl("https://example.com/page/");
		assert.ok(!result.endsWith("/"));
	});

	it("keeps trailing slash for root path", () => {
		// Root URL: pathname is "/"
		const result = normalizeUrl("https://example.com");
		assert.ok(result.includes("example.com"));
	});

	it("strips tracking parameters", () => {
		const result = normalizeUrl("https://example.com/page?utm_source=test&id=123");
		assert.ok(!result.includes("utm_source"));
		assert.ok(result.includes("id=123"));
	});

	it("strips fbclid", () => {
		const result = normalizeUrl("https://example.com/page?fbclid=abc&foo=bar");
		assert.ok(!result.includes("fbclid"));
		assert.ok(result.includes("foo=bar"));
	});

	it("sorts query parameters", () => {
		const result = normalizeUrl("https://example.com/page?z=1&a=2&m=3");
		assert.ok(result.indexOf("a=2") < result.indexOf("m=3"));
		assert.ok(result.indexOf("m=3") < result.indexOf("z=1"));
	});

	it("strips hash fragment", () => {
		const result = normalizeUrl("https://example.com/page#section");
		assert.ok(!result.includes("#section"));
	});
});

describe("urlsMatch", () => {
	it("matches identical URLs", () => {
		assert.equal(urlsMatch("https://example.com", "https://example.com"), true);
	});

	it("matches after normalization", () => {
		assert.equal(
			urlsMatch("https://example.com/page/", "https://example.com/page"),
			true,
		);
	});

	it("matches with different tracking params", () => {
		assert.equal(
			urlsMatch("https://example.com/page?utm_source=a&id=1", "https://example.com/page?id=1"),
			true,
		);
	});

	it("does not match different paths", () => {
		assert.equal(
			urlsMatch("https://example.com/a", "https://example.com/b"),
			false,
		);
	});
});

describe("dedupUrls", () => {
	it("removes duplicate URLs", () => {
		const result = dedupUrls([
			"https://example.com/a",
			"https://example.com/b",
			"https://example.com/a/",
		]);
		assert.equal(result.length, 2);
	});

	it("preserves first occurrence form", () => {
		const result = dedupUrls([
			"https://example.com/page?utm_source=test",
			"https://example.com/page",
		]);
		assert.equal(result.length, 1);
		assert.equal(result[0], "https://example.com/page?utm_source=test");
	});
});

describe("dedupSearchResults", () => {
	it("deduplicates search results by URL", () => {
		const results = [
			{ title: "A", url: "https://example.com/1", snippet: "", source: "test" },
			{ title: "B", url: "https://example.com/2", snippet: "", source: "test" },
			{ title: "C", url: "https://example.com/1/", snippet: "", source: "test" },
		];
		const deduped = dedupSearchResults(results);
		assert.equal(deduped.length, 2);
		assert.equal(deduped[0]?.title, "A");
		assert.equal(deduped[1]?.title, "B");
	});
});

import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { synthesize, type SourceContent } from "../../src/research/synthesize.ts";

describe("synthesize", () => {
	it("returns empty results for no sources", () => {
		const result = synthesize("test query", []);
		assert.equal(result.summary, 'No sources found for query: "test query"');
		assert.equal(result.findings.length, 0);
		assert.equal(result.contradictions.length, 0);
	});

	it("produces findings from sources", () => {
		const sources: SourceContent[] = [
			{
				url: "https://example.com/1",
				title: "Source 1",
				snippet: "TypeScript is a typed superset of JavaScript.",
				content: "TypeScript is a typed superset of JavaScript that compiles to plain JavaScript. It provides static type checking and modern language features. TypeScript improves developer productivity and code quality through type safety.",
			},
			{
				url: "https://example.com/2",
				title: "Source 2",
				snippet: "TypeScript adds types to JavaScript.",
				content: "TypeScript adds optional static typing to JavaScript. It supports interfaces, generics, and type inference. TypeScript code is transpiled to JavaScript for execution.",
			},
		];
		const result = synthesize("What is TypeScript?", sources);
		assert.ok(result.summary.length > 0);
		assert.ok(result.findings.length > 0);
		assert.ok(result.recommendations.length > 0);
	});

	it("detects contradictions between sources", () => {
		const sources: SourceContent[] = [
			{
				url: "https://a.com",
				title: "Pro",
				snippet: "You should use TypeScript.",
				content: "You should always use TypeScript for production applications. TypeScript provides type safety that prevents runtime errors and improves code maintainability significantly.",
			},
			{
				url: "https://b.com",
				title: "Con",
				snippet: "You should not use TypeScript.",
				content: "You should not always use TypeScript. TypeScript adds compilation overhead and complexity. For small projects, JavaScript is often sufficient and more productive.",
			},
		];
		const result = synthesize("Should I use TypeScript?", sources);
		// May or may not detect contradictions depending on keyword matching
		assert.ok(result.contradictions.length >= 0);
	});

	it("assigns higher confidence with more sources", () => {
		const sources: SourceContent[] = Array.from({ length: 5 }, (_, i) => ({
			url: `https://example.com/${i}`,
			title: `Source ${i}`,
			snippet: `Finding about topic alpha beta gamma.`,
			content: `Finding about topic alpha beta gamma. This is a detailed analysis of the subject with supporting evidence and examples from real world usage.`,
		}));
		const result = synthesize("test", sources);
		// With 5 similar sources, at least one finding should have high/medium confidence
		const confidences = result.findings.map((f) => f.confidence);
		assert.ok(
			confidences.includes("high") || confidences.includes("medium"),
			"Expected at least one medium or high confidence finding",
		);
	});

	it("generates recommendations", () => {
		const sources: SourceContent[] = [
			{
				url: "https://example.com",
				title: "Source",
				snippet: "Test",
				content: "This is a test source with enough content to generate findings about the queried topic.",
			},
		];
		const result = synthesize("test query", sources);
		assert.ok(result.recommendations.length > 0);
	});
});

