import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { loadConfig, getDefaults } from "../../src/config.ts";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

function createTempDir(): string {
	return fs.mkdtempSync(path.join(os.tmpdir(), "pi-web-research-test-"));
}

describe("loadConfig", () => {
	it("returns defaults when no config file exists", () => {
		const tmpDir = createTempDir();
		try {
			const config = loadConfig(tmpDir);
			assert.equal(config.enabled, true);
			assert.equal(config.search.defaultEngine, "auto");
			assert.equal(config.search.maxResults, 5);
			assert.equal(config.fetch.maxTokens, 5000);
			assert.equal(config.cache.enabled, true);
		} finally {
			fs.rmSync(tmpDir, { recursive: true, force: true });
		}
	});

	it("loads config from .pi/pi-web-research.json", () => {
		const tmpDir = createTempDir();
		try {
			const piDir = path.join(tmpDir, ".pi");
			fs.mkdirSync(piDir, { recursive: true });
			fs.writeFileSync(path.join(piDir, "pi-web-research.json"), JSON.stringify({
				enabled: false,
				search: { maxResults: 10 },
			}));

			const config = loadConfig(tmpDir);
			assert.equal(config.enabled, false);
			assert.equal(config.search.maxResults, 10);
			// Other defaults preserved
			assert.equal(config.fetch.maxTokens, 5000);
		} finally {
			fs.rmSync(tmpDir, { recursive: true, force: true });
		}
	});

	it("resolves API keys from env vars", () => {
		const tmpDir = createTempDir();
		try {
			process.env.BRAVE_API_KEY = "test-brave-key";
			process.env.GEMINI_API_KEY = "test-gemini-key";
			process.env.EXA_API_KEY = "test-exa-key";

			const config = loadConfig(tmpDir);
			assert.equal(config.apiKeys.brave, "test-brave-key");
			assert.equal(config.apiKeys.gemini, "test-gemini-key");
			assert.equal(config.apiKeys.exa, "test-exa-key");
		} finally {
			delete process.env.BRAVE_API_KEY;
			delete process.env.GEMINI_API_KEY;
			delete process.env.EXA_API_KEY;
			fs.rmSync(tmpDir, { recursive: true, force: true });
		}
	});

	it("config values take priority over env vars", () => {
		const tmpDir = createTempDir();
		try {
			const piDir = path.join(tmpDir, ".pi");
			fs.mkdirSync(piDir, { recursive: true });
			fs.writeFileSync(path.join(piDir, "pi-web-research.json"), JSON.stringify({
				apiKeys: *** brave: "config-key" },
			}));
			process.env.BRAVE_API_KEY = "env-key";

			const config = loadConfig(tmpDir);
			assert.equal(config.apiKeys.brave, "config-key");
		} finally {
			delete process.env.BRAVE_API_KEY;
			fs.rmSync(tmpDir, { recursive: true, force: true });
		}
	});

	it("handles malformed config gracefully", () => {
		const tmpDir = createTempDir();
		try {
			const piDir = path.join(tmpDir, ".pi");
			fs.mkdirSync(piDir, { recursive: true });
			fs.writeFileSync(path.join(piDir, "pi-web-research.json"), "not json {{{");

			const config = loadConfig(tmpDir);
			assert.equal(config.enabled, true); // Falls back to defaults
		} finally {
			fs.rmSync(tmpDir, { recursive: true, force: true });
		}
	});
});

describe("getDefaults", () => {
	it("returns a copy of defaults", () => {
		const d1 = getDefaults();
		const d2 = getDefaults();
		assert.deepEqual(d1, d2);
		// Mutating one doesn't affect the other
		d1.enabled = false;
		assert.equal(d2.enabled, true);
	});
});

