function makeConfig(overrides: Partial<WebResearchConfig> = {}): WebResearchConfig {
	return {
		enabled: true,
		search: { defaultEngine: "auto", fallbackChain: ["duckduckgo"], maxResults: 3, ...overrides.search },
		fetch: { maxTokens: ***, timeout: 5000, userAgent: "Test/1.0", ...overrides.fetch },
		cache: { enabled: false, maxAgeHours: 1, maxSizeMB: 1, ...overrides.cache },
		apiKeys: *** brave: "", gemini: "", exa: "", ...overrides.apiKeys },
		fallback: { onAllProvidersFail: "return_empty_with_suggestion", suggestion: "No providers." },
	};
}

