/** Get a cached entry by URL. Returns null if not found or expired. */
get(url: string): CacheEntry | null {
	this.ensureOpen();
	const now = Date.now();
	const row = this.db.prepare(
		"SELECT url, content, content_type AS contentType, fetched_at AS fetchedAt, expires_at AS expiresAt, size_bytes AS sizeBytes FROM cache_entries WHERE url = ? AND expires_at > ?",
	).get(url, now) as CacheEntry | undefined;
	return row ?? null;
}

