import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { createEngine, type FallbackChainConfig } from "../../src/search/fallback-chain.ts";

describe("fallbackSearch", () => {
	it("creates correct engine instances", () => {
		const engines = ["brave", "gemini", "exa", "duckduckgo"];
		for (const name of engines) {
			const engine = createEngine(name, {
				brave: "test-key",
				gemini: "test-key",
				exa: "test-key",
			});
			assert.equal(engine.name, name);
		}
	});

	it("throws for unknown engine", () => {
		assert.throws(() => createEngine("unknown", {}), /Unknown search engine/);
	});

	it("brave engine is unavailable without API key", () => {
		const engine = createEngine("brave", { brave: "" });
		assert.equal(engine.isAvailable(), false);
	});

	it("brave engine is available with API key", () => {
		const engine = createEngine("brave", { brave: "test-key" });
		assert.equal(engine.isAvailable(), true);
	});

	it("duckduckgo engine is always available", () => {
		const engine = createEngine("duckduckgo", {});
		assert.equal(engine.isAvailable(), true);
	});

	it("config chain has correct structure", () => {
		const config: FallbackChainConfig = {
			chain: ["brave", "gemini", "exa", "duckduckgo"],
			apiKeys: ***},
		};
		assert.ok(Array.isArray(config.chain));
		assert.equal(config.chain.length, 4);
		assert.equal(config.chain[0], "brave");
		assert.equal(config.chain[3], "duckduckgo");
	});
});
